#include <iostream>
#include <string>
using namespace std;

// 1. БАЗОВИЙ КЛАС
class Animal {
protected: // Замінили private на protected, щоб Собака та Кіт мали доступ
    string name;
    int age;

public:
    Animal(string n, int a) : name(n), age(a) { }

    void sleep() {
        cout << name << " зараз міцно спить... Zzz" << endl;
    }
};


// 2. КЛАС СПАДКОЄМЕЦЬ (Dog успадковує ВСЕ у Animal)
class Dog : public Animal {
private:
    string breed; // Унікальне поле собаки (тварина абстрактна породи не має)

public:
    // Конструктор Собаки ПЕПЕРЕДАЄ ім'я та вік до конструктора Animal
    Dog(string n, int a, string b) : Animal(n, a), breed(b) { }

    void bark() {
        // Доступ до name можливий, бо воно protected в батькові!
        cout << "[" << breed << "] " << name << " каже: Гав-Гав!" << endl;
    }
};


// 3. ЩЕ ОДИН СПАДКОЄМЕЦЬ (Кішка) 
class Cat : public Animal {
public:
    Cat(string n, int a) : Animal(n, a) {}

    void meow() {
        cout << name << " каже: Мяу! І просить їсти." << endl;
    }
};


int main() {
    Dog rex("Рекс", 4, "Вівчарка");
    Cat murka("Мурка", 2);

    // Ми можемо викликати sleep(), бо Dog і Cat його успішно УСПАДКУВАЛИ
    cout << "
==== Вечір ====" << endl;
    rex.sleep(); 
    murka.sleep();

    // АЛЕ унікальні методи існують тільки для конкретних класів
    cout << "
==== Ранок ====" << endl;
    rex.bark(); 
    murka.meow();

    return 0;
}
